package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves the filtered JSON to the specified file.
// It returns the JSON that was written to the file and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic validation to ensure required parameters are provided
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("loadBalancerName and outputFile must be non-empty")
	}

	// 1. Run the aliyun CLI command to describe SLBs
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunOut, err := aliyunCmd.Output()
	if err != nil {
		// If the command exited with an error, try to include stderr for diagnostics
		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, string(exitErr.Stderr))
		}
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// 2. Pipe the aliyun JSON output into jq to extract the LoadBalancer array
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = bytes.NewReader(aliyunOut)

	var jqOut bytes.Buffer
	jqCmd.Stdout = &jqOut

	if err := jqCmd.Run(); err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, string(exitErr.Stderr))
		}
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// 3. Write the filtered JSON to the requested output file
	if err := os.WriteFile(outputFile, jqOut.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	// Return the JSON string that was written to the file
	return jqOut.String(), nil
}

// main demonstrates a simple usage of QuerySLBAndExport
func main() {
	// Example: query an SLB named "myLoadBalancer" and save the result to "output.json"
	result, err := QuerySLBAndExport("myLoadBalancer", "output.json")
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Println("Output successfully written to output.json")
	fmt.Println("Result:")
	fmt.Println(result)
}

