package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport runs the aliyun CLI to query SLB information,
// processes the JSON output with jq, writes the result to outputFile,
// and returns the captured output (the JSON array) as a string.
// Any error encountered during execution is returned.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// ---------- Input validation ----------
	// Whitelist allowed characters for the load balancer name.
	if !isValidInput(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: contains disallowed characters")
	}
	// Restrict output file to relative paths without path traversal.
	if !isValidPath(outputFile) {
		return "", fmt.Errorf("invalid output file path: contains disallowed characters")
	}

	// ---------- Prepare aliyun command ----------
	// Pass arguments directly to avoid shell injection.
	aliyunCmd := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)

	// Create a pipe from aliyun's stdout.
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun: %w", err)
	}

	// ---------- Prepare jq command ----------
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout

	// Capture jq's stdout to return and also write to the file.
	var stdoutBuf bytes.Buffer
	jqCmd.Stdout = &stdoutBuf

	// Capture any stderr from jq for error reporting.
	var stderrBuf bytes.Buffer
	jqCmd.Stderr = &stderrBuf

	// ---------- Execute the pipeline ----------
	// Start aliyun (it will block on writing to stdout until we read).
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq.
	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun process.
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish; this also closes the pipe automatically,
	// signalling EOF to jq.
	if err := aliyunCmd.Wait(); err != nil {
		// Even if aliyun fails, let jq attempt to finish processing.
		_ = jqCmd.Wait()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq to finish reading the data.
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// ---------- Write result to file ----------
	// Create (or truncate) the output file.
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Write the captured JSON array to the file.
	if _, err := outFile.Write(stdoutBuf.Bytes()); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	// Return the captured output to the caller.
	return stdoutBuf.String(), nil
}

// isValidInput checks that a string only contains allowed characters.
// Allowed: alphanumeric, dash, underscore, dot and space.
func isValidInput(s string) bool {
	for _, c := range s {
		if !strings.ContainsRune("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_ .", c) {
			return false
		}
	}
	return true
}

// isValidPath ensures the output file does not use absolute paths or
// path traversal sequences.
func isValidPath(s string) bool {
	if strings.HasPrefix(s, "/") || strings.Contains(s, "..") {
		return false
	}
	return !strings.ContainsAny(s, "\\")
}

// ---------- Example usage ----------
func main() {
	// Example: read parameters from environment variables or use defaults.
	name := os.Getenv("SLB_NAME")
	output := os.Getenv("SLB_OUTPUT")
	if name == "" {
		name = "my-loadbalancer"
	}
	if output == "" {
		output = "output.json"
	}

	result, err := QuerySLBAndExport(name, output)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", result)
		os.Exit(1)
	}
	fmt.Printf("SLB information exported to %s\n", output)
}

