func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build the pipeline command string.
	// Note: In production, proper quoting should be applied to prevent injection issues.
	cmdStr := fmt.Sprintf(
		"aliyun slb DescribeLoadBalancers --LoadBalancerName %s | jq '.LoadBalancers.LoadBalancer[]' > %s",
		loadBalancerName,
		outputFile,
	)

	// Execute the pipeline via sh -c
	cmd := exec.Command("sh", "-c", cmdStr)

	// Capture stdout and stderr
	output, err := cmd.CombinedOutput()
	if err != nil {
		// Return the captured output together with the error
		return string(output), err
	}

	// Read the file that was written and return its content
	fileContent, err := os.ReadFile(outputFile)
	if err != nil {
		// If we cannot read the file, fall back to returning the command output
		return string(output), err
	}

	return string(fileContent), nil
}

func main() {
	// Example usage: replace the arguments with actual values
