	// Properly escape single quotes to prevent breaking out of single-quoted shell strings
	escapeShellParam := func(s string) string {
		return strings.ReplaceAll(s, "'", "'\\''")
	}

	escapedName := escapeShellParam(loadBalancerName)
	escapedOutput := escapeShellParam(outputFile)

	// Use tee to capture output while writing to file
	cmdStr := fmt.Sprintf("aliyun slb DescribeLoadBalancers --LoadBalancerName '%s' | jq '.LoadBalancers.LoadBalancer[]' | tee '%s'",
		escapedName, escapedOutput)

	cmd := exec.Command("sh", "-c", cmdStr)

	outputBytes, err := cmd.CombinedOutput()
	outputStr := string(outputBytes)

	if err != nil {
		return outputStr, fmt.Errorf("command failed: %w", err)
	}

	return outputStr, nil
}

