import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strings"
)

// QuerySLBAndExport runs the aliyun CLI to describe SLB, filters the JSON
// output with jq, and writes the result to the specified file.
// It returns the jq output (the JSON array) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate loadBalancerName: only allow safe characters.
	if !regexp.MustCompile(`^[a-zA-Z0-9._-]+$`).MatchString(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: contains disallowed characters")
	}

	// Validate outputFile: prevent directory traversal and absolute paths.
	if strings.Contains(outputFile, "..") || strings.HasPrefix(outputFile, "/") {
		return "", fmt.Errorf("invalid outputFile path")
	}

	// Run aliyun CLI directly without a shell to avoid injection.
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	var aliyunOut bytes.Buffer
	var aliyunErr bytes.Buffer
	aliyunCmd.Stdout = &aliyunOut
	aliyunCmd.Stderr = &aliyunErr

	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunErr.String())
	}

	// Pipe the aliyun output into jq.
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = bytes.NewReader(aliyunOut.Bytes())

	var jqOut bytes.Buffer
	var jqErr bytes.Buffer
	jqCmd.Stdout = &jqOut
	jqCmd.Stderr = &jqErr

	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqErr.String())
	}

	// Write the filtered JSON to the requested file.
	if err := os.WriteFile(outputFile, jqOut.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	// Return the jq output for callers that need it.
	return jqOut.String(), nil
}

func main() {
	// Example usage (replace the parameters with actual values).
	result, err := QuerySLBAndExport("my-loadbalancer", "output.json")
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}
	fmt.Println("Result:", result)
}

