// QuerySLBAndExport runs the aliyun CLI command to describe SLB,
// pipes the JSON result through jq, writes the transformed output
// to the specified file and returns the captured output (the JSON
// array) together with any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// ----- Input validation -------------------------------------------------
	// The name should contain only safe characters.
	if !isValidName(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: only alphanumeric, hyphen and underscore allowed")
	}
	// The output path must not contain shell metacharacters.
	if !isValidPath(outputFile) {
