	}

	// ----- Prepare aliyun command -------------------------------------------
	// Arguments are passed as separate strings to avoid shell injection.
	aliyunArgs := []string{"slb", "DescribeLoadBalancers"}
	if loadBalancerName != "" {
		aliyunArgs = append(aliyunArgs, "--LoadBalancerName", loadBalancerName)
	}
	aliyunCmd := exec.Command("aliyun", aliyunArgs...)

	// ----- Prepare jq command -----------------------------------------------
	jqCmd := exec.Command("jq", `.LoadBalancers.LoadBalancer[]`)

	// ----- Create output file ------------------------------------------------
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// We'll capture the jq output in a buffer *and* write it to the file.
	var buf bytes.Buffer
	jqCmd.Stdout = io.MultiWriter(outFile, &buf)

	// ----- Connect the two commands with a pipe -----------------------------
	aliyunOut, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun: %w", err)
	}
	jqCmd.Stdin = aliyunOut

	// Propagate stderr for debugging.
	aliyunCmd.Stderr = os.Stderr
	jqCmd.Stderr = os.Stderr

	// ----- Run the commands -------------------------------------------------
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun: %w", err)
	}
	if err := jqCmd.Start(); err != nil {
		// Clean up the aliyun process if jq fails to start.
		aliyunCmd.Process.Kill()
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Wait for aliyun to finish; then close its stdout pipe so jq gets EOF.
	if err := aliyunCmd.Wait(); err != nil {
		aliyunOut.Close()
