		if !(c == '-' || c == '_' || (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9')) {
			return false
		}
	}
	return true
}

// isValidPath checks that the output file path does not contain shell metacharacters.
func isValidPath(path string) bool {
	if path == "" {
