	aliyunOut, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get aliyun stdout pipe: %w", err)
	}
	// Let aliyun print errors to our stderr.
	aliyunCmd.Stderr = os.Stderr

