package main

import (
	"flag"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport runs the aliyun SLB query, pipes the result through jq,
// and writes the formatted JSON to the specified output file.
// It returns the combined stdout/stderr from the command pipeline and any
// error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build the pipeline command string.
	// We rely on the environment having the `aliyun` CLI configured
	// and `jq` installed.
	cmdStr := fmt.Sprintf(
		"aliyun slb DescribeLoadBalancers --LoadBalancerName %s | jq '.LoadBalancers.LoadBalancer[]' > %s",
		loadBalancerName,
		outputFile,
	)

	// Execute the pipeline through a shell.
	cmd := exec.Command("sh", "-c", cmdStr)

	// Capture combined stdout and stderr.
	out, err := cmd.CombinedOutput()
	if err != nil {
		// Return the captured output along with the error.
		return string(out), err
	}

	// On success, the formatted JSON has already been written to the file.
	// Return an empty string (or the captured output if you prefer).
	return string(out), nil
}

func main() {
	// Define command‑line flags.
	name := flag.String("name", "", "Load Balancer Name")
	output := flag.String("output", "output.json", "Output file")
	flag.Parse()

	// Validate required parameters.
	if *name == "" {
		fmt.Println("Error: -name flag is required")
		os.Exit(1)
	}

	// Run the query and export.
	result, err := QuerySLBAndExport(*name, *output)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error executing command: %v\n", err)
		fmt.Fprintf(os.Stderr, "Command output: %s\n", result)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB information to %s\n", *output)
	if result != "" {
		fmt.Println("Command output:", result)
	}
}

