package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It returns the combined output (stdout/stderr) of the command pipeline
// and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic validation: ensure parameters are not empty.
	if loadBalancerName == "" {
		return "", errors.New("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", errors.New("outputFile cannot be empty")
	}

	// Only allow safe characters (alphanumeric, period, underscore, hyphen, forward slash)
	safePattern := regexp.MustCompile(`^[a-zA-Z0-9._/-]+$`)
	if !safePattern.MatchString(loadBalancerName) || !safePattern.MatchString(outputFile) {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Use "sh -c" with positional parameters to safely pass user-provided arguments.
	// The script redirects the jq output to the user‑specified file.
	// $1 -> loadBalancerName, $2 -> outputFile
	// The first extra argument ("dummy") corresponds to $0 in the script.
	cmd := exec.Command(
		"sh", "-c",
		`aliyun slb DescribeLoadBalancers --LoadBalancerName "$1" | jq '.LoadBalancers.LoadBalancer[]' > "$2"`,
		"dummy", // $0 (unused)
		loadBalancerName, // $1
		outputFile, // $2
	)

	// Capture both stdout and stderr.
	output, err := cmd.CombinedOutput()
	outStr := string(output)

	if err != nil {
		return outStr, fmt.Errorf("command failed: %w, output: %s", err, outStr)
	}

	return outStr, nil
}

func main() {
	// Simple CLI usage: ./program <LoadBalancerName> <outputFile>
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <LoadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	lbName := os.Args[1]
	outFile := os.Args[2]

	result, err := QuerySLBAndExport(lbName, outFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		if result != "" {
			fmt.Fprintln(os.Stderr, "Command output:", result)
		}
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB info to %s\n", outFile)
	if result != "" {
		fmt.Println("Command output:", result)
	}
}

