package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs to prevent shell injection
	// Check for shell metacharacters that could be used for injection
	invalidChars := "`$\n\r\t|>;&\\\"'<>(){}[]"
	if strings.ContainsAny(loadBalancerName, invalidChars) {
		return "", fmt.Errorf("invalid characters in loadBalancerName")
	}
	if strings.ContainsAny(outputFile, invalidChars) {
		return "", fmt.Errorf("invalid characters in outputFile")
	}

	// Execute the aliyun command directly without shell
	// Using multiple arguments prevents shell interpretation
	cmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Get output from aliyun command
	aliyunOutput, err := cmd.Output()
	if err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, output: %s", err, string(aliyunOutput))
	}

	// Execute jq command with the aliyun output as stdin
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = strings.NewReader(string(aliyunOutput))

	jqOutput, err := jqCmd.Output()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w, output: %s", err, string(jqOutput))
	}

	// Write to output file directly without shell redirection
	err = os.WriteFile(outputFile, jqOutput, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(jqOutput), nil
}

