package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// escapeShell wraps a string in single quotes and escapes any embedded single quotes,
// making it safe to embed in a shell command string.
func escapeShell(s string) string {
	// Replace each single quote with '\'' (end quote, escaped quote, start quote)
	return "'" + strings.ReplaceAll(s, "'", "'\\''") + "'"
}

// QuerySLBAndExport runs the aliyun CLI to query SLB information,
// processes the JSON with jq, and writes the result to the specified file.
// It returns the combined output (stdout/stderr) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic validation: reject strings containing control characters that are
	// unlikely to be part of a valid name/path.
	if strings.ContainsAny(loadBalancerName, "\x00\x1f") || strings.ContainsAny(outputFile, "\x00\x1f") {
		return "", fmt.Errorf("invalid control characters in input parameters")
	}

	// Build the pipeline command with proper quoting to prevent injection.
	cmdStr := fmt.Sprintf(
		"aliyun slb DescribeLoadBalancers --LoadBalancerName %s | jq '.LoadBalancers.LoadBalancer[]' > %s",
		escapeShell(loadBalancerName),
		escapeShell(outputFile),
	)

	// Use sh -c to let the shell interpret the pipeline and I/O redirection.
	cmd := exec.Command("sh", "-c", cmdStr)

	// Capture stdout and stderr for reporting.
	var outBuf bytes.Buffer
	cmd.Stdout = &outBuf
	cmd.Stderr = &outBuf

	// Execute the command.
	if err := cmd.Run(); err != nil {
		return outBuf.String(), fmt.Errorf("command failed: %w, output: %s", err, outBuf.String())
	}

	// The actual result has been written to outputFile; return the captured output.
	return outBuf.String(), nil
}

// Example usage (can be removed in production).
func main() {
	// Example: query an SLB named "my-load-balancer" and write to "slb.json".
	name := "my-load-balancer"
	outFile := "slb.json"

	output, err := QuerySLBAndExport(name, outFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\nOutput: %s\n", err, output)
		os.Exit(1)
	}
	fmt.Println("SLB data exported to", outFile)
}

