package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Execute the aliyun command directly without shell to avoid injection
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Capture stdout and stderr
	aliyunOutput, err := aliyunCmd.CombinedOutput()
	if err != nil {
		return string(aliyunOutput), fmt.Errorf("aliyun command failed: %w, output: %s", err, aliyunOutput)
	}

	// Execute jq with the aliyun output as stdin
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = strings.NewReader(string(aliyunOutput))

	jqOutput, err := jqCmd.CombinedOutput()
	if err != nil {
		return string(jqOutput), fmt.Errorf("jq command failed: %w, output: %s", err, jqOutput)
	}

	// Write the output to the specified file
	err = os.WriteFile(outputFile, jqOutput, 0644)
	if err != nil {
		return string(jqOutput), fmt.Errorf("failed to write output file: %w", err)
	}

	return string(jqOutput), nil
}

